// Vendor JavaScript - Required libraries initialization
// This file initializes third-party libraries

document.addEventListener('DOMContentLoaded', function() {
    // Initialize Lenis smooth scrolling
    if (typeof Lenis !== 'undefined') {
        const lenis = new Lenis({
            duration: 1.2,
            easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
            direction: 'vertical',
            gestureDirection: 'vertical',
            smooth: true,
            smoothTouch: false,
            touchMultiplier: 2,
        });

        function raf(time) {
            lenis.raf(time);
            requestAnimationFrame(raf);
        }
        requestAnimationFrame(raf);
    }

    // Initialize Swiper sliders if they exist
    if (typeof Swiper !== 'undefined') {
        // Services slider
        if (document.querySelector('.services-slide')) {
            new Swiper('.services-slide', {
                slidesPerView: 1,
                spaceBetween: 30,
                centeredSlides: false,
                preventClicks: true,
                loop: false,
                autoHeight: true,
                autoplay: {
                    delay: 5000,
                    disableOnInteraction: false,
                    pauseOnMouseEnter: true,
                },
                pagination: {
                    clickable: true,
                    el: '.swiper-pagination-services',
                },
                breakpoints: {
                    0: { slidesPerView: 1 },
                    768: { slidesPerView: 2 },
                    992: { slidesPerView: 2.9 },
                    1200: { slidesPerView: 3 }
                }
            });
        }

        // Projects slider
        if (document.querySelector('.projects-slide')) {
            new Swiper('.projects-slide', {
                slidesPerView: 1,
                spaceBetween: 30,
                loop: true,
                autoHeight: true,
                navigation: {
                    nextEl: '.prev1',
                    prevEl: '.next1',
                },
                breakpoints: {
                    0: { slidesPerView: 1 },
                    768: { slidesPerView: 2 },
                    992: { slidesPerView: 2.9 },
                    1200: { slidesPerView: 3 }
                }
            });
        }

        // Testimonial slider
        if (document.querySelector('.testimonial-slide')) {
            new Swiper('.testimonial-slide', {
                slidesPerView: 1,
                spaceBetween: 0,
                loop: true,
                autoHeight: true,
                navigation: {
                    nextEl: '.prev2',
                    prevEl: '.next2',
                }
            });
        }

        // Team slider
        if (document.querySelector('.team-slide')) {
            new Swiper('.team-slide', {
                slidesPerView: 1,
                spaceBetween: 30,
                loop: true,
                pagination: {
                    el: '.swiper-pagination-team',
                    clickable: true,
                },
                breakpoints: {
                    0: { slidesPerView: 1 },
                    768: { slidesPerView: 2 },
                    992: { slidesPerView: 3 },
                    1200: { slidesPerView: 4 }
                }
            });
        }

        // Partner slider
        if (document.querySelector('.partner-slide')) {
            new Swiper('.partner-slide', {
                slidesPerView: 2,
                spaceBetween: 30,
                loop: true,
                autoplay: {
                    delay: 3000,
                    disableOnInteraction: false,
                    pauseOnMouseEnter: true,
                },
                breakpoints: {
                    0: { slidesPerView: 2 },
                    768: { slidesPerView: 4 },
                    1200: { slidesPerView: 6 }
                }
            });
        }
    }

    // Initialize scrollCue animations if available
    if (typeof scrollCue !== 'undefined') {
        scrollCue.init({
            duration: 900,
            change: 0,
            delay: 0,
            scale: 1,
            timing: 'ease',
        });
    }
});
